    if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] !== 1) return 0;
    grid[r][c] = label;
    return 1 + dfs(r+1,c,label) + dfs(r-1,c,label) + dfs(r,c+1,label) + dfs(r,c-1,label);
  }
  for (let i = 0; i < n; i++)
    for (let j = 0; j < n; j++)
      if (grid[i][j] === 1) { sizes[id] = dfs(i, j, id); id++; }
  let max = Math.max(0, ...Object.values(sizes));
  for (let i = 0; i < n; i++)
    for (let j = 0; j < n; j++)
      if (grid[i][j] === 0) {
        const seen = new Set();
        let total = 1;
        for (const [dr, dc] of dirs) {
          const nr = i+dr, nc = j+dc;
